package com.enterprise.api;

import com.enterprise.api.dto.CreateUserRequest;
import com.enterprise.domain.UserAccount;
import com.enterprise.service.UserManagementService;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserManagementService userManagementService;

    public UserController(UserManagementService userManagementService) {
        this.userManagementService = userManagementService;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public UserAccount create(@Valid @RequestBody CreateUserRequest req) {
        return userManagementService.createUser(req.getUsername(), req.getEmail(), req.getPasswordHash());
    }

    @GetMapping("/{id}")
    public UserAccount get(@PathVariable Long id) {
        return userManagementService.findById(id).orElseThrow(() -> new jakarta.persistence.EntityNotFoundException("User not found"));
    }
}

