package com.enterprise.api;

import com.enterprise.api.dto.CreateTransactionRequest;
import com.enterprise.domain.AccountTransaction;
import com.enterprise.service.TransactionProcessingService;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/transactions")
public class TransactionController {

    private final TransactionProcessingService transactionProcessingService;

    public TransactionController(TransactionProcessingService transactionProcessingService) {
        this.transactionProcessingService = transactionProcessingService;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public AccountTransaction create(@Valid @RequestBody CreateTransactionRequest req) {
        return transactionProcessingService.createTransaction(
                req.getUserId(),
                req.getAmount(),
                req.getType(),
                req.getReferenceId(),
                req.getMemo()
        );
    }

    @PostMapping("/{referenceId}/posted")
    public AccountTransaction posted(@PathVariable String referenceId) {
        return transactionProcessingService.markPosted(referenceId);
    }

    @PostMapping("/{referenceId}/failed")
    public AccountTransaction failed(@PathVariable String referenceId, @RequestParam(required = false) String memo) {
        return transactionProcessingService.markFailed(referenceId, memo);
    }
}

